class Solution {
    public int minSwaps(int[] nums) {
        int totalOnes = 0;
        for (int num : nums) {
            if (num == 1) totalOnes++;
        }
        if (totalOnes == 0) return 0;

        int n = nums.length;
        int windowSize = totalOnes;
        int maxOnes = 0;
        int currentOnes = 0;
        int left = 0;

        for (int right = 0; right < 2 * n; right++) {
            int index = right % n;
            if (nums[index] == 1) {
                currentOnes++;
            }

            if (right >= windowSize - 1) {
                if (currentOnes > maxOnes) {
                    maxOnes = currentOnes;
                }

                int leftIndex = left % n;
                if (nums[leftIndex] == 1) {
                    currentOnes--;
                }
                left++;
            }
        }

        return windowSize - maxOnes;
    }
}

